#[cfg(test)]
mod biber_eval_tests {
    use super::*;

    #[test]
    fn checked_adds_amounts() {
        let total = XriqAmount::new(2).checked_add(XriqAmount::new(3)).unwrap();
        assert_eq!(total.as_u64(), 5);
    }

    #[test]
    fn detects_overflow() {
        assert!(XriqAmount::new(u64::MAX).checked_add(XriqAmount::new(1)).is_none());
    }
}

#[cfg(test)]
mod biber_eval_tests {
    use super::*;

    #[test]
    fn accepts_valid_transaction() {
        let tx = Transaction {
            from: "alice".to_string(),
            to: "bob".to_string(),
            amount: 10,
            nonce: 1,
        };
        assert!(validate_transaction(&tx).is_ok());
    }

    #[test]
    fn rejects_zero_amount_and_blank_sender() {
        let zero = Transaction {
            from: "alice".to_string(),
            to: "bob".to_string(),
            amount: 0,
            nonce: 1,
        };
        assert!(validate_transaction(&zero).is_err());

        let blank_sender = Transaction {
            from: "   ".to_string(),
            to: "bob".to_string(),
            amount: 1,
            nonce: 1,
        };
        assert!(validate_transaction(&blank_sender).is_err());
    }
}

#[cfg(test)]
mod biber_eval_tests {
    use super::*;

    #[test]
    fn calculates_basic_fee() {
        assert_eq!(calculate_fee(250, 2), Some(500));
    }

    #[test]
    fn returns_none_on_overflow() {
        assert_eq!(calculate_fee(usize::MAX, u64::MAX), None);
    }
}

#[cfg(test)]
mod biber_eval_tests {
    use super::*;
    use std::collections::HashSet;

    #[test]
    fn detects_duplicate_transactions() {
        let mut mempool = HashSet::new();
        assert!(insert_tx(&mut mempool, "tx-1".to_string()));
        assert!(!insert_tx(&mut mempool, "tx-1".to_string()));
        assert_eq!(mempool.len(), 1);
    }
}

#[cfg(test)]
mod biber_eval_tests {
    use super::*;

    #[test]
    fn advances_height() {
        let header = BlockHeader {
            height: 41,
            previous_hash: [0; 32],
            timestamp_ms: 1000,
        };
        assert_eq!(next_height(&header), Some(42));
    }

    #[test]
    fn detects_height_overflow() {
        let header = BlockHeader {
            height: u64::MAX,
            previous_hash: [0; 32],
            timestamp_ms: 1000,
        };
        assert_eq!(next_height(&header), None);
    }
}

